import{_ as a,c as l,o as s,a0 as e}from"./chunks/framework.zS86-xgI.js";const t="/note-operator/network/external/shadowsocks/008.png",r="/note-operator/network/external/shadowsocks/003.png",i="/note-operator/network/external/shadowsocks/004.png",n="/note-operator/network/external/shadowsocks/005.png",p="/note-operator/network/external/shadowsocks/006.png",c="/note-operator/network/external/shadowsocks/017.png",d="/note-operator/network/external/shadowsocks/018.png",h="/note-operator/network/external/shadowsocks/007.png",w="/note-operator/network/external/shadowsocks/009.png",f=JSON.parse('{"title":"安装shadowsocks客户端","description":"","frontmatter":{},"headers":[],"relativePath":"markdown/network/external/shadowsocks/02.md","filePath":"markdown/network/external/shadowsocks/02.md"}'),k={name:"markdown/network/external/shadowsocks/02.md"};function _(m,o,u,g,x,b){return s(),l("div",null,o[0]||(o[0]=[e('<h1 id="安装shadowsocks客户端" tabindex="-1">安装shadowsocks客户端 <a class="header-anchor" href="#安装shadowsocks客户端" aria-label="Permalink to &quot;安装shadowsocks客户端&quot;">​</a></h1><p>查找版本到shadowsocks的github主页上自己找 <a href="https://github.com/shadowsocks" target="_blank" rel="noreferrer">github.com/shadowsocks</a></p><h2 id="_1-1-安装windows版" tabindex="-1">1.1 安装windows版 <a class="header-anchor" href="#_1-1-安装windows版" aria-label="Permalink to &quot;1.1 安装windows版&quot;">​</a></h2><h3 id="_1-1-1-安装并使用" tabindex="-1">1.1.1 安装并使用 <a class="header-anchor" href="#_1-1-1-安装并使用" aria-label="Permalink to &quot;1.1.1 安装并使用&quot;">​</a></h3><ol><li><p>Windows软件地址:</p><p><a href="https://github.com/shadowsocks/shadowsocks-windows/releases" target="_blank" rel="noreferrer">https://github.com/shadowsocks/shadowsocks-windows/releases</a></p><p><img src="'+t+'" alt="" data-fancybox="gallery"></p></li><li><p>运行并配置</p><ul><li><p>文件目录</p><p><img src="'+r+'" alt="" data-fancybox="gallery"></p></li><li><p>配置信息</p><p><img src="'+i+'" alt="" data-fancybox="gallery"></p></li><li><p>设置上网模式</p><p><img src="'+n+'" alt="" data-fancybox="gallery"></p></li></ul></li><li><p>浏览器连接谷歌网站</p><p><img src="'+p+'" alt="" data-fancybox="gallery"></p></li></ol><h3 id="_1-1-2-模式区分" tabindex="-1">1.1.2 模式区分 <a class="header-anchor" href="#_1-1-2-模式区分" aria-label="Permalink to &quot;1.1.2 模式区分&quot;">​</a></h3><p>在软件中的模式</p><p><img src="'+c+'" alt="" data-fancybox="gallery"></p><ol><li><p>PAC 模式 (智能分流) PAC 代表“代理自动配置 (Proxy Auto-Config)”，是 Shadowsocks 的默认且推荐模式。</p><ul><li>工作原理：客户端会根据一个名为 pac.txt 的文件（包含像 GFWList 这样的黑名单）来判断。</li><li>分流表现： <ul><li>墙外网站（如 Google, YouTube）：走代理，通过服务器访问。</li><li>国内网站（如 百度, 淘宝）：不走代理，直接连接。</li></ul></li><li>优点：省流量（服务器流量），访问国内网站速度快（延迟低），不影响本地网络服务。</li></ul></li><li><p>全局模式 (Global Mode)</p><ul><li>工作原理：无视规则，强制将所有流量通过代理服务器转发。</li><li>表现：无论是 Google 还是百度，所有请求都会先经过你的代理服务器。</li><li>适用场景： <ul><li>某个国外网站不在 PAC 列表里，但你又懒得去手动改 PAC。</li><li>需要隐藏所有访问踪迹或通过特定 IP 访问任何资源。</li></ul></li><li>缺点：浪费服务器流量；由于绕路，访问国内网站会变慢且可能导致部分国内 App（如音乐、视频）因版权限制（识别为国外 IP）无法使用。</li></ul></li></ol><h3 id="_1-1-2-pac模式的使用" tabindex="-1">1.1.2 PAC模式的使用 <a class="header-anchor" href="#_1-1-2-pac模式的使用" aria-label="Permalink to &quot;1.1.2 PAC模式的使用&quot;">​</a></h3><p>问题：这个软件长时间不更新，PAC也常时间没有更新</p><ol><li><p>更新PAC规则</p><p><img src="'+d+'" alt="" data-fancybox="gallery"></p></li><li><p>添加PAC规则</p><ul><li><p>方法一：通过“用户自定规则”添加（推荐） 这是最简单、最安全的方法，不会破坏原有的 PAC 结构。</p><ol><li>打开菜单：右键点击任务栏的 Shadowsocks 图标。</li><li>选择编辑：找到 “PAC 模式”（或“PAC 设置”），点击 “编辑 PAC 用户自定规则...” (Edit User Rules for PAC)。</li><li>添加规则：在弹出的文本文件中，每行输入一个规则。常用格式如下： <ul><li><code>||example.com</code>：匹配该域名及其所有子域名走代理。</li><li><code>@@||example.com</code>：匹配该域名及其所有子域名不走代理（白名单）。</li></ul></li><li>保存并更新：保存该文件，然后再次右键点击 SS 图标，选择 “从 GFWList 更新 PAC”（或类似“从本地文件更新”）以使规则生效。</li></ol></li><li><p>方法二：直接修改 pac.txt 文件</p><p>如果你需要修改更复杂的逻辑（如端口或特定 IP 范围），可以直接操作源文件。</p><ol><li>定位文件：PAC 文件通常位于 Shadowsocks 程序的根目录下，文件名为 pac.txt。</li><li>编辑内容：使用记事本或代码编辑器打开。该文件是 JavaScript 代码，核心函数为 FindProxyForURL(url, host)。 <ul><li>你可以在 rules 数组部分手动插入域名规则。</li><li>注意：直接修改此文件后，如果执行了“从 GFWList 更新 PAC”，你的手动改动可能会被覆盖。</li></ul></li></ol></li></ul></li></ol><h2 id="_1-2-安装andriod" tabindex="-1">1.2 安装andriod <a class="header-anchor" href="#_1-2-安装andriod" aria-label="Permalink to &quot;1.2 安装andriod&quot;">​</a></h2><ol><li><p>安卓app地址:</p><p><a href="https://github.com/shadowsocks/shadowsocks-android/releases" target="_blank" rel="noreferrer">https://github.com/shadowsocks/shadowsocks-android/releases</a></p><p><img src="'+h+'" alt="" data-fancybox="gallery"></p></li><li><p>选择联通</p><p><img src="'+w+'" alt="" data-fancybox="gallery"></p></li></ol>',14)]))}const A=a(k,[["render",_]]);export{f as __pageData,A as default};
